/* ============================================================
   Pipeline 类型定义 — P1 修复 (C-1)

   定义 Pipe-and-Filter 流水线的核心接口:
     - PipelineStep: 每个处理单元的标准接口
     - PipelineContext: 在 Step 间传递的统一数据载体
     - PipelineConfig: 声明式流程配置
   ============================================================ */

import type {
  ConversationState, IntentType, AgentResponse,
  JobPosition, ParsedResume,
} from '../types';

// ============================================================
// Step 错误处理策略
// ============================================================

export type StepErrorStrategy = 'halt' | 'skip' | 'retry' | 'fallback';

// ============================================================
// Step 执行结果
// ============================================================

export interface StepResult {
  /** Step 是否成功执行 */
  success: boolean;
  /** 错误信息（仅 success=false 时有值） */
  error?: string;
  /** Step 输出指标（耗时、token 用量等） */
  metrics?: Record<string, unknown>;
  /** 是否跳过后续 Step（提前终止流水线） */
  stopPipeline?: boolean;
}

// ============================================================
// PipelineContext — 统一数据载体
// ============================================================

export interface PipelineContext {
  // === 会话 ===
  conversationId: string;
  /** 当前会话状态 */
  state: ConversationState;
  /** 流水线起始时的快照（用于回滚） */
  initialState: ConversationState;

  // === 岗位 ===
  currentJobId: string | null;
  jobs: JobPosition[];

  // === 简历 ===
  parsedResumes: ParsedResume[];
  pendingResume: ParsedResume | null;

  // === 用户输入 ===
  userMessage: string;
  /** 原始用户消息（未清理 @提及） */
  rawMessage: string;

  // === 流水线内部 ===
  /** 当前处理的意图 */
  intent?: IntentType;
  /** Step 间传递的中间结果 */
  intermediates: Map<string, unknown>;
  /** 日志收集（每个 Step 可追加） */
  logs: Array<{ step: string; level: 'debug' | 'info' | 'warn' | 'error'; message: string }>;
  /** Step 执行顺序记录 */
  executionPath: string[];

  // === 最终输出 ===
  /** 最终要返回给用户/Store 的响应 */
  response?: AgentResponse;
  /** 是否需要更新岗位 */
  jobUpdate?: JobPosition;
  /** 是否需要持久化简历 */
  resumeUpdate?: ParsedResume;
}

// ============================================================
// PipelineStep — Step 标准接口
// ============================================================

export interface PipelineStep {
  /** Step 唯一标识 */
  readonly name: string;

  /** Step 描述（用于日志和调试） */
  readonly description: string;

  /** 该 Step 依赖的前置 Step（名称列表），空数组表示无依赖 */
  readonly dependencies: string[];

  /** 是否启用（可通过配置关闭） */
  readonly enabled: boolean;

  /** 错误处理策略 */
  readonly onError: StepErrorStrategy;

  /** 最大重试次数（仅 onError='retry' 时有效） */
  readonly maxRetries: number;

  /**
   * 执行 Step 的核心逻辑
   *
   * @param ctx - 流水线上下文
   * @returns 执行结果（success/error + 指标）。Step 可以修改 ctx（可变传递）
   */
  execute(ctx: PipelineContext): Promise<StepResult>;
}

// ============================================================
// PipelineConfig — 声明式配置
// ============================================================

export interface PipelineConfig {
  /** 流水线名称 */
  name: string;
  /** 流水线版本 */
  version: string;
  /** 要执行的 Step 列表（按依赖拓扑排序） */
  steps: PipelineStep[];
  /** 全局超时（毫秒），0 表示无限制 */
  timeout: number;
  /** 是否启用并行执行（无依赖的 Step 并发执行） */
  parallel: boolean;
}

// ============================================================
// 工具函数
// ============================================================

/** 创建空的 PipelineContext */
export function createPipelineContext(
  userMessage: string,
  state: ConversationState,
  overrides?: Partial<Pick<PipelineContext, 'currentJobId' | 'jobs' | 'parsedResumes' | 'pendingResume'>>,
): PipelineContext {
  return {
    conversationId: `conv_${Date.now()}`,
    state,
    initialState: state,
    currentJobId: overrides?.currentJobId ?? null,
    jobs: overrides?.jobs ?? [],
    parsedResumes: overrides?.parsedResumes ?? [],
    pendingResume: overrides?.pendingResume ?? null,
    userMessage,
    rawMessage: userMessage,
    intermediates: new Map(),
    logs: [],
    executionPath: [],
  };
}

/* ============================================================
   Zustand 全局状态管理
   管理：会话列表、消息、状态机、岗位、简历、UI状态
   ============================================================ */

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type {
  ConversationState, ChatMessage, JobPosition, ParsedResume,
  ConversationContext, ThemeMode, QuickAction, CandidateScore,
} from '../types';
import { canTransition } from '../lib/state-machine';

export interface RecruitmentStore {
  // === 会话 ===
  conversationId: string;
  messages: ChatMessage[];
  state: ConversationState;

  // === 岗位管理 ===
  jobs: JobPosition[];
  currentJobId: string | null;
  pendingResume: ParsedResume | null;

  // === 简历管理 ===
  parsedResumes: ParsedResume[];
  screeningResult: {
    totalResumes: number;
    scoredResumes: number;
    recommendedCount: number;
    topCandidates: CandidateScore[];
    generatedAt: number;
  } | null;

  // === UI 状态 ===
  theme: ThemeMode;
  isTyping: boolean;
  showFilePicker: boolean;
  quickActions: QuickAction[];
  sidebarOpen: boolean;
  /** Sidebar 快捷操作触发的待处理动作文本（ChatInput 侦听处理） */
  sceneAction: string | null;

  // === Actions ===
  addMessage: (msg: Omit<ChatMessage, 'id' | 'timestamp'>) => void;
  setTyping: (typing: boolean) => void;
  setState: (state: ConversationState) => void;
  setTheme: (theme: ThemeMode) => void;

  // 岗位操作
  addJob: (job: JobPosition) => void;
  updateJob: (jobId: string, updates: Partial<JobPosition>) => void;
  setCurrentJob: (jobId: string | null) => void;

  // 简历操作
  addResume: (resume: ParsedResume) => void;
  assignResumeToJob: (resumeId: string, jobId: string) => void;
  setPendingResume: (resume: ParsedResume | null) => void;

  // 筛选
  setScreeningResult: (result: RecruitmentStore['screeningResult']) => void;

  // UI actions
  setQuickActions: (actions: QuickAction[]) => void;
  setShowFilePicker: (show: boolean) => void;
  toggleSidebar: () => void;
  /** Sidebar 快捷操作触发 */
  triggerSceneAction: (text: string) => void;
  clearSceneAction: () => void;

  // 重置
  reset: () => void;

  // 获取上下文
  getContext: () => ConversationContext;
}

const initialState = {
  conversationId: 'conv_' + Date.now(),
  messages: [] as ChatMessage[],
  state: 'IDLE' as ConversationState,
  jobs: [] as JobPosition[],
  currentJobId: null as string | null,
  pendingResume: null as ParsedResume | null,
  parsedResumes: [] as ParsedResume[],
  screeningResult: null as RecruitmentStore['screeningResult'],
  theme: 'system' as ThemeMode,
  isTyping: false,
  showFilePicker: false,
  quickActions: [] as QuickAction[],
  sidebarOpen: true,
  sceneAction: null as string | null,
};

export const useRecruitmentStore = create<RecruitmentStore>()(
  persist(
    (set, get) => ({
      ...initialState,

      addMessage: (msg) => {
        const newMsg: ChatMessage = {
          ...msg,
          id: 'msg_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8),
          timestamp: Date.now(),
        };
        set(state => ({ messages: [...state.messages, newMsg] }));
      },

      setTyping: (typing) => set({ isTyping: typing }),

      setState: (newState) => {
        // P1 修复 (B-5): 状态转换校验
        const currentState = get().state;
        const result = canTransition(currentState, newState);
        if (!result.allowed) {
          console.warn(`[Store.setState] ${result.reason} (当前: ${currentState}, 目标: ${newState})`);
          // 开发阶段记录警告但允许转换，避免硬阻断导致用户卡死
          // 生产环境可切换为严格拦截
        }
        set({ state: newState });
      },

      setTheme: (theme) => {
        set({ theme });
        applyTheme(theme);
      },

      addJob: (job) => {
        set(state => ({
          jobs: [...state.jobs, job],
          currentJobId: job.id,
        }));
      },

      updateJob: (jobId, updates) => {
        set(state => ({
          jobs: state.jobs.map(j => j.id === jobId ? { ...j, ...updates } : j),
        }));
      },

      setCurrentJob: (jobId) => set({ currentJobId: jobId }),

      addResume: (resume) => {
        set(state => ({
          parsedResumes: [...state.parsedResumes, resume],
          pendingResume: null,
        }));
      },

      assignResumeToJob: (resumeId, jobId) => {
        set(state => {
          const updatedResumes = state.parsedResumes.map(r =>
            r.id === resumeId ? { ...r, jobId } : r
          );
          const jobResumes = updatedResumes.filter(r => r.jobId === jobId);
          return {
            parsedResumes: updatedResumes,
            jobs: state.jobs.map(j =>
              j.id === jobId ? { ...j, resumeCount: jobResumes.length } : j
            ),
          };
        });
      },

      setPendingResume: (resume) => set({ pendingResume: resume }),

      setScreeningResult: (result) => set({ screeningResult: result }),

      setQuickActions: (actions) => set({ quickActions: actions }),

      setShowFilePicker: (show) => set({ showFilePicker: show }),

      toggleSidebar: () => set(state => ({ sidebarOpen: !state.sidebarOpen })),

      triggerSceneAction: (text) => set({ sceneAction: text }),

      clearSceneAction: () => set({ sceneAction: null }),

      reset: () => {
        set({
          ...initialState,
          conversationId: 'conv_' + Date.now(),
          theme: get().theme,
        });
      },

      getContext: () => {
        const state = get();
        return {
          currentJobId: state.currentJobId,
          jobs: state.jobs,
          parsedResumes: state.parsedResumes,
          pendingResume: state.pendingResume || undefined,
        };
      },
    }),
    {
      name: 'recruitment-agent-storage',
      partialize: (state) => ({
        messages: state.messages.slice(-200), // 只持久化最近200条消息
        state: state.state,
        jobs: state.jobs,
        currentJobId: state.currentJobId,
        parsedResumes: state.parsedResumes,
        screeningResult: state.screeningResult,
        theme: state.theme,
        conversationId: state.conversationId,
      }),
    }
  )
);

// 应用主题
function applyTheme(theme: ThemeMode) {
  const root = document.documentElement;
  const isDark = theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);
  root.classList.toggle('dark', isDark);
}

// 初始化主题
if (typeof window !== 'undefined') {
  const stored = localStorage.getItem('recruitment-agent-storage');
  if (stored) {
    try {
      const parsed = JSON.parse(stored);
      if (parsed.state?.theme) {
        applyTheme(parsed.state.theme);
      }
    } catch { /* ignore */ }
  }
}

/* ============================================================
   智能招聘智能体 - 核心类型定义
   PRD v1.2 | MVP 最小闭环
   ============================================================ */

// === 会话状态机（PRD 7.2.1：6个状态） ===
export type ConversationState =
  | 'IDLE'               // 空闲，等待指令
  | 'JD_GENERATING'      // 正在生成JD
  | 'JD_CONFIRMING'      // JD已生成，等待确认
  | 'COLLECTING'         // 等待HR提交简历
  | 'SCREENING'          // 正在评分
  | 'SCREENING_RESULT';  // 报告已推送

// === 意图类型（PRD 4.2.1） ===
export type IntentType =
  | 'GENERATE_JD'
  | 'MODIFY_JD'
  | 'MODIFY_RESUME'
  | 'CONFIRM_JD'
  | 'SUBMIT_RESUME'
  | 'SCREEN_RESUMES'
  | 'QUERY_PROGRESS'
  | 'VIEW_DETAIL'
  | 'FALLBACK';

// === 岗位数据 ===
export interface JobPosition {
  id: string;
  title: string;
  department: string;
  location: string;
  reportTo: string;
  headcount: number;
  responsibilities: string[];
  hardRequirements: string[];
  bonusRequirements: string[];
  status: 'draft' | 'active' | 'closed';
  createdAt: number;
  resumeCount: number;
}

// === 简历解析结果（PRD US-2） ===
export interface ParsedResume {
  id: string;
  jobId: string;
  name: string;
  age?: number;
  degree: string;
  school: string;
  major: string;
  workYears: number;
  city: string;
  experiences: WorkExperience[];
  skills: string[];
  confidence: 'high' | 'medium' | 'low';
  parsedAt: number;
  fileName: string;
  /** 标记哪些关键字段解析失败（空），前端可显示"待补充" */
  missingFields?: string[];
  /** 【v1.4】原始简历文本 — 用于前端对照核查解析准确性 */
  originalText?: string;
  /** 【v1.4】原始文件类型 */
  sourceFileType?: 'pdf' | 'word' | 'txt';
}

export interface WorkExperience {
  role: string;
  company: string;
  period: string;
  duration: string;
}

// === 评分维度（PRD US-3：5维度，各0-20分） ===
export interface ScoreDimension {
  name: string;
  score: number;        // 0-20
  maxScore: number;     // 20
  reason: string;       // 评分理由
  matchedKeywords: string[];
  gaps: string[];
}

export interface CandidateScore {
  resumeId: string;
  candidateName: string;
  totalScore: number;   // 0-100
  dimensions: ScoreDimension[];
  highlight: string;
  rank?: number;
}

// === 筛选报告 ===
export interface ScreeningReport {
  jobId: string;
  jobTitle: string;
  totalResumes: number;
  scoredResumes: number;
  recommendedCount: number;
  topCandidates: CandidateScore[];
  generatedAt: number;
}

// === 进度摘要 ===
export interface ProgressSummary {
  jobId: string;
  jobTitle: string;
  state: ConversationState;
  jdGenerated: boolean;
  jdConfirmed: boolean;
  resumeCount: number;
  parsedCount: number;
  scoredCount: number;
  recommendedCount: number;
  lastOperation: string;
  lastOperator: string;
  lastOperatedAt: number;
}

// === 聊天消息 ===
export type MessageType = 'system' | 'user' | 'user_file' | 'bot_text' | 'bot_card';

export interface ChatMessage {
  id: string;
  type: MessageType;
  content: string;
  timestamp: number;
  sender?: string;
  file?: FileAttachment;
  cardType?: CardType;
  cardData?: unknown;
  quickActions?: QuickAction[];
}

export interface FileAttachment {
  name: string;
  size: string;
  type: 'pdf' | 'word' | 'image' | 'text';
}

export type CardType = 'jd' | 'resume_parse' | 'screening_report' | 'progress' | 'detail' | 'analysis' | 'error';

export interface QuickAction {
  label: string;
  action: string;
  primary?: boolean;
}

// === Agent 交互 ===
export interface AgentRequest {
  conversationId: string;
  groupId: string;
  message: string;
  state: ConversationState;
  context: ConversationContext;
}

export interface ConversationContext {
  currentJobId: string | null;
  jobs: JobPosition[];
  parsedResumes: ParsedResume[];
  pendingResume?: ParsedResume;
}

export interface AgentResponse {
  type: MessageType;
  content: string;
  cardType?: CardType;
  cardData?: unknown;
  quickActions?: QuickAction[];
  newState?: ConversationState;
  jobUpdate?: Partial<JobPosition>;
  resumeUpdate?: Partial<ParsedResume>;
}

// === 会话 ===
export interface Conversation {
  id: string;
  title: string;
  messages: ChatMessage[];
  state: ConversationState;
  context: ConversationContext;
  createdAt: number;
  updatedAt: number;
}

// === 主题 ===
export type ThemeMode = 'light' | 'dark' | 'system';

/* ============================================================
   测试套件: 意图识别规则引擎 (intent-rules.ts)
   覆盖: 所有状态×意图组合、中英文混合、边界输入
   ============================================================ */

import { describe, it, expect } from 'vitest';
import { matchIntent } from '../lib/intent-rules';
import type { ConversationState } from '../types';

// ============================================================
// 1. 简历修改意图 = 最高优先级
// ============================================================
describe('意图识别 — MODIFY_RESUME (最高优先级)', () => {
  const states: ConversationState[] = ['IDLE', 'JD_GENERATING', 'JD_CONFIRMING', 'COLLECTING', 'SCREENING', 'SCREENING_RESULT'];

  const modifyResumeInputs = [
    '修改姓名：周宇瑞；工作年限：0',
    '更正学历为硕士，姓名改为李四',
    '调整工作年限为5年',
    '更新学校信息为清华大学',
    '修改专业：计算机科学',
    '修改技能：增加 Python 和 Java',
    '纠正城市信息，应该是深圳',
    '修改简历中的经历',
    '调整年龄为28岁',
  ];

  states.forEach(state => {
    modifyResumeInputs.forEach(input => {
      it(`[${state}] "${input.slice(0, 30)}..." → MODIFY_RESUME`, () => {
        expect(matchIntent(input, state)).toBe('MODIFY_RESUME');
      });
    });
  });

  it('仅有修改词但不含简历字段 → 不应匹配 MODIFY_RESUME', () => {
    expect(matchIntent('修改一下JD，地点改成深圳', 'JD_CONFIRMING')).not.toBe('MODIFY_RESUME');
  });

  it('仅有简历字段但无修改词 → 不应匹配 MODIFY_RESUME', () => {
    expect(matchIntent('姓名：张三，学历硕士', 'IDLE')).toBeNull();
  });
});

// ============================================================
// 2. JD 确认 → 修改JD（仅 JD_CONFIRMING 状态）
// ============================================================
describe('意图识别 — MODIFY_JD (JD_CONFIRMING状态)', () => {
  it('修改地点 → MODIFY_JD', () => {
    expect(matchIntent('把JD地点改成深圳', 'JD_CONFIRMING')).toBe('MODIFY_JD');
  });

  it('加上技能要求 → MODIFY_JD', () => {
    expect(matchIntent('加上Python要求', 'JD_CONFIRMING')).toBe('MODIFY_JD');
  });

  it('调整人数 → MODIFY_JD', () => {
    expect(matchIntent('调整人数为3人', 'JD_CONFIRMING')).toBe('MODIFY_JD');
  });

  it('非 JD_CONFIRMING 状态下的修改词 → 不返回 MODIFY_JD', () => {
    expect(matchIntent('加上Python要求', 'IDLE')).toBeNull();
  });
});

// ============================================================
// 3. JD 确认（短确认词）
// ============================================================
describe('意图识别 — CONFIRM_JD', () => {
  const confirmInputs = ['确认', '好的', '行', 'OK', '没问题', '可以', 'Yes'];

  confirmInputs.forEach(input => {
    it(`[JD_CONFIRMING] "${input}" → CONFIRM_JD`, () => {
      expect(matchIntent(input, 'JD_CONFIRMING')).toBe('CONFIRM_JD');
    });
  });

  it('确认词长度 >= 10 → 不返回 CONFIRM_JD', () => {
    expect(matchIntent('确认没问题就这样吧我觉得可以了', 'JD_CONFIRMING')).toBeNull();
  });

  it('非 JD_CONFIRMING 状态下的确认 → 应返回 null（让LLM处理）', () => {
    expect(matchIntent('确认', 'IDLE')).toBeNull();
  });
});

// ============================================================
// 4. JD 生成
// ============================================================
describe('意图识别 — GENERATE_JD', () => {
  const jdInputs = [
    '帮我招一个前端开发',
    '招聘一名芯片验证工程师',
    '生成JD：AI产品经理',
    'hire a software engineer',
    '新岗位：数据分析师',
  ];

  jdInputs.forEach(input => {
    it(`"${input}" → GENERATE_JD`, () => {
      expect(matchIntent(input, 'IDLE')).toBe('GENERATE_JD');
    });
  });

  it('含"招"和"进度" → 应返回 QUERY_PROGRESS（优先进度）', () => {
    expect(matchIntent('招聘进度怎么样', 'IDLE')).toBe('QUERY_PROGRESS');
  });
});

// ============================================================
// 5. 筛选评分
// ============================================================
describe('意图识别 — SCREEN_RESUMES', () => {
  it('筛选 → SCREEN_RESUMES', () => {
    expect(matchIntent('开始筛选', 'COLLECTING')).toBe('SCREEN_RESUMES');
  });

  it('评分 → SCREEN_RESUMES', () => {
    expect(matchIntent('给这些简历打分', 'COLLECTING')).toBe('SCREEN_RESUMES');
  });

  it('看看这批 → SCREEN_RESUMES', () => {
    expect(matchIntent('看看这批怎么样', 'COLLECTING')).toBe('SCREEN_RESUMES');
  });
});

// ============================================================
// 6. 进度查询
// ============================================================
describe('意图识别 — QUERY_PROGRESS', () => {
  it('查看进度 → QUERY_PROGRESS', () => {
    expect(matchIntent('查看招聘进度', 'COLLECTING')).toBe('QUERY_PROGRESS');
  });

  it('多少份 → QUERY_PROGRESS', () => {
    expect(matchIntent('现在收到多少份简历了', 'COLLECTING')).toBe('QUERY_PROGRESS');
  });

  it('情况怎么样 → QUERY_PROGRESS', () => {
    expect(matchIntent('情况怎么样', 'SCREENING_RESULT')).toBe('QUERY_PROGRESS');
  });
});

// ============================================================
// 7. 查看详情
// ============================================================
describe('意图识别 — VIEW_DETAIL', () => {
  it('[SCREENING_RESULT] 查看某人详情 → VIEW_DETAIL', () => {
    expect(matchIntent('查看张三的详情', 'SCREENING_RESULT')).toBe('VIEW_DETAIL');
  });

  it('查看评分 → VIEW_DETAIL', () => {
    expect(matchIntent('查看评分', 'IDLE')).toBe('VIEW_DETAIL');
  });
});

// ============================================================
// 8. 提交简历
// ============================================================
describe('意图识别 — SUBMIT_RESUME', () => {
  it('长文本(>200字符) → SUBMIT_RESUME', () => {
    const longText = 'A'.repeat(201);
    expect(matchIntent(longText, 'IDLE')).toBe('SUBMIT_RESUME');
  });

  it('短文本(<200字符) → 不返回SUBMIT_RESUME', () => {
    expect(matchIntent('这是一个短消息', 'IDLE')).toBeNull();
  });
});

// ============================================================
// 9. 边界/异常输入
// ============================================================
